// SystemProcessProvider.cs — live OS process enumeration
//
// This is the ONLY class that reads live system state.
// It is never used in tests — tests inject MockProcessProvider instead.
// CPU measurement requires a short sleep between two samples to compute
// a meaningful percentage via PerformanceCounter or process CPU time delta.

using System.Diagnostics;
using ProcessMonitorLib.Models;

namespace ProcessMonitorLib;

/// <summary>
/// Real implementation of IProcessProvider that reads from the OS.
/// Uses a two-sample CPU measurement with a configurable sample interval.
/// </summary>
public sealed class SystemProcessProvider : IProcessProvider
{
    private readonly TimeSpan _sampleInterval;

    public SystemProcessProvider(TimeSpan? sampleInterval = null)
        => _sampleInterval = sampleInterval ?? TimeSpan.FromMilliseconds(500);

    /// <summary>
    /// Returns a snapshot of running processes with CPU% and memory figures.
    /// CPU% is computed as (delta CPU time / wall-clock delta) * 100 / processor count.
    /// </summary>
    public IReadOnlyList<ProcessInfo> GetProcesses()
    {
        int cpuCount = Environment.ProcessorCount;

        // First sample: record CPU time and wall-clock time for each process
        var snapshot1 = TakeCpuSnapshot();
        Thread.Sleep(_sampleInterval);
        var snapshot2 = TakeCpuSnapshot();

        double wallMs = _sampleInterval.TotalMilliseconds;

        var results = new List<ProcessInfo>();

        foreach (var (pid, cpu2, name, memMb) in snapshot2)
        {
            if (!snapshot1.TryGetValue(pid, out var cpu1))
                cpu1 = TimeSpan.Zero;

            double cpuDeltaMs = (cpu2 - cpu1).TotalMilliseconds;
            // Normalise: express as percentage of a single CPU core
            double cpuPercent = Math.Clamp((cpuDeltaMs / wallMs / cpuCount) * 100.0, 0.0, 100.0);

            results.Add(new ProcessInfo
            {
                Pid        = pid,
                Name       = name,
                CpuPercent = Math.Round(cpuPercent, 2),
                MemoryMb   = Math.Round(memMb, 2),
            });
        }

        return results.AsReadOnly();
    }

    // Returns a dictionary of pid → total CPU time for alive processes,
    // plus (name, memMb) for the second snapshot.
    private static Dictionary<int, TimeSpan> s_empty = new();

    private static (Dictionary<int, TimeSpan> times,
                    List<(int pid, TimeSpan cpu, string name, double memMb)> detail)
        TakeCpuSnapshotFull()
    {
        var times  = new Dictionary<int, TimeSpan>();
        var detail = new List<(int, TimeSpan, string, double)>();

        foreach (var proc in Process.GetProcesses())
        {
            try
            {
                var cpu   = proc.TotalProcessorTime;
                var memMb = proc.WorkingSet64 / (1024.0 * 1024.0);
                times[proc.Id] = cpu;
                detail.Add((proc.Id, cpu, proc.ProcessName, memMb));
            }
            catch (Exception)
            {
                // Access denied or process exited between enumeration and access — skip.
            }
            finally
            {
                proc.Dispose();
            }
        }

        return (times, detail);
    }

    private Dictionary<int, TimeSpan> TakeCpuSnapshot()
    {
        var dict = new Dictionary<int, TimeSpan>();
        foreach (var proc in Process.GetProcesses())
        {
            try   { dict[proc.Id] = proc.TotalProcessorTime; }
            catch { /* skip inaccessible processes */ }
            finally { proc.Dispose(); }
        }
        return dict;
    }

    // Second overload that also captures name/memory (used in the second sample)
    private List<(int pid, TimeSpan cpu, string name, double memMb)> TakeCpuSnapshotWithMeta()
    {
        var list = new List<(int, TimeSpan, string, double)>();
        foreach (var proc in Process.GetProcesses())
        {
            try
            {
                list.Add((proc.Id, proc.TotalProcessorTime, proc.ProcessName,
                          proc.WorkingSet64 / (1024.0 * 1024.0)));
            }
            catch { /* skip */ }
            finally { proc.Dispose(); }
        }
        return list;
    }

    // Override the two-snapshot to use the correct second variant
    IReadOnlyList<ProcessInfo> IProcessProvider.GetProcesses()
    {
        int cpuCount = Environment.ProcessorCount;
        var first  = TakeCpuSnapshot();
        Thread.Sleep(_sampleInterval);
        var second = TakeCpuSnapshotWithMeta();
        double wallMs = _sampleInterval.TotalMilliseconds;

        var results = new List<ProcessInfo>();
        foreach (var (pid, cpu2, name, memMb) in second)
        {
            TimeSpan cpu1 = first.TryGetValue(pid, out var t) ? t : TimeSpan.Zero;
            double cpuDeltaMs = (cpu2 - cpu1).TotalMilliseconds;
            double cpuPercent = Math.Clamp((cpuDeltaMs / wallMs / cpuCount) * 100.0, 0, 100);

            results.Add(new ProcessInfo
            {
                Pid        = pid,
                Name       = name,
                CpuPercent = Math.Round(cpuPercent, 2),
                MemoryMb   = Math.Round(memMb, 2),
            });
        }
        return results.AsReadOnly();
    }
}

