    /// <summary>
    /// Returns a snapshot of running processes with CPU% and memory figures.
    /// CPU% is computed as (delta CPU time / wall-clock delta) * 100 / processor count.
    /// </summary>
    public IReadOnlyList<ProcessInfo> GetProcesses()
    {
        int cpuCount = Environment.ProcessorCount;

        // First sample: record CPU time and wall-clock time for each process
        var snapshot1 = TakeCpuSnapshot();
        Thread.Sleep(_sampleInterval);
        var snapshot2 = TakeCpuSnapshot();

        double wallMs = _sampleInterval.TotalMilliseconds;

        var results = new List<ProcessInfo>();

        foreach (var (pid, cpu2, name, memMb) in snapshot2)
        {
            if (!snapshot1.TryGetValue(pid, out var cpu1))
                cpu1 = TimeSpan.Zero;

            double cpuDeltaMs = (cpu2 - cpu1).TotalMilliseconds;
            // Normalise: express as percentage of a single CPU core
            double cpuPercent = Math.Clamp((cpuDeltaMs / wallMs / cpuCount) * 100.0, 0.0, 100.0);

            results.Add(new ProcessInfo
            {
                Pid        = pid,
                Name       = name,
                CpuPercent = Math.Round(cpuPercent, 2),
                MemoryMb   = Math.Round(memMb, 2),
            });
        }

        return results.AsReadOnly();
    }

    // Returns a dictionary of pid → total CPU time for alive processes,
    // plus (name, memMb) for the second snapshot.
    private static Dictionary<int, TimeSpan> s_empty = new();

    private static (Dictionary<int, TimeSpan> times,
                    List<(int pid, TimeSpan cpu, string name, double memMb)> detail)
        TakeCpuSnapshotFull()
    {
        var times  = new Dictionary<int, TimeSpan>();
        var detail = new List<(int, TimeSpan, string, double)>();

        foreach (var proc in Process.GetProcesses())
        {
