// ProcessMonitor.cs — .NET 10 file-based app entry point
// Run with:  dotnet run ProcessMonitor.cs [--cpu <pct>] [--mem <mb>] [--top <n>]
//
// Uses the live SystemProcessProvider when run as a script.
// All business logic lives in ProcessMonitorLib so it can be unit-tested
// with mock data independently of this entry point.
//
// The #:project directive tells the .NET 10 file-based-app runner to
// compile and reference the library project automatically.

#:project ProcessMonitorLib/ProcessMonitorLib.csproj

using ProcessMonitorLib;
using ProcessMonitorLib.Models;
using ProcessMonitorLib.Services;

// ── Parse CLI arguments ──────────────────────────────────────────────────────
double cpuThreshold  = 80.0;
double memThresholdMb = 1024.0;
int    topN           = 5;

for (int i = 0; i < args.Length - 1; i++)
{
    switch (args[i].ToLowerInvariant())
    {
        case "--cpu" or "-c":
            if (double.TryParse(args[i + 1], out double c)) cpuThreshold = c;
            break;
        case "--mem" or "-m":
            if (double.TryParse(args[i + 1], out double m)) memThresholdMb = m;
            break;
        case "--top" or "-n":
            if (int.TryParse(args[i + 1], out int n)) topN = n;
            break;
    }
}

var config = new ThresholdConfig
{
    CpuThresholdPercent = cpuThreshold,
    MemoryThresholdMb   = memThresholdMb,
    TopN                = topN,
};

// ── Validate config before doing any work ───────────────────────────────────
var monitor = new ProcessMonitorService();
try
{
    monitor.ValidateConfig(config);
}
catch (ArgumentException ex)
{
    Console.Error.WriteLine($"[ERROR] Invalid configuration: {ex.Message}");
    Environment.Exit(1);
}

// ── Collect live process data ────────────────────────────────────────────────
Console.WriteLine("Collecting process data (500 ms sample)...");
IProcessProvider provider = new SystemProcessProvider();

IReadOnlyList<ProcessInfo> processes;
try
{
    processes = provider.GetProcesses();
}
catch (Exception ex)
{
    Console.Error.WriteLine($"[ERROR] Failed to read process list: {ex.Message}");
    Environment.Exit(2);
    return; // unreachable — satisfies nullable flow analysis
}

// ── Generate and print report ────────────────────────────────────────────────
var report = monitor.GenerateReport(processes, config);
Console.WriteLine(report.FormatAsText());

// ── Exit code: 0 = no alerts, 1 = alerts found ──────────────────────────────
Environment.Exit(report.Summary.CpuAlertsCount > 0 || report.Summary.MemoryAlertsCount > 0
    ? 1  // signals "alerts present" to calling scripts
    : 0);

