        var processes = provider.GetProcesses();
        var report = monitor.GenerateReport(processes, config);

        Assert.Empty(report.CpuAlerts);
        Assert.Empty(report.MemoryAlerts);
        Assert.Equal(0, report.Summary.TotalProcessesScanned);
